CREATE TABLE TB_AMANAJE_CLI (
    ID_CLIENTE NUMBER GENERATED BY DEFAULT AS IDENTITY,
    NM_CLI VARCHAR2(150) NOT NULL,
    TP_CLI VARCHAR2(30) NOT NULL,
    NR_DOCUMENTO VARCHAR2(30),
    DS_EMAIL_CONTATO VARCHAR2(200),
    NR_TELEFONE VARCHAR2(30),
    ST_ATIVO CHAR(1) DEFAULT 'S' NOT NULL,
    DT_CRIADO_EM TIMESTAMP DEFAULT SYSTIMESTAMP NOT NULL,
    DT_ATUALIZADO_EM TIMESTAMP,
    DT_DEL_EM TIMESTAMP,
    ID_DEL_POR NUMBER,
    DS_MOTIVO_EXCLUSAO VARCHAR2(255),

    CONSTRAINT PK_AMANAJE_CLI PRIMARY KEY (ID_CLIENTE),
    CONSTRAINT UQ_AMANAJE_CLI_DOC UNIQUE (NR_DOCUMENTO),
    CONSTRAINT CK_AMANAJE_CLI_TIPO CHECK (TP_CLI IN ('GOVERNO_DEFESA_CIVIL', 'ONG', 'FAZENDA_PRIVADO', 'COOPERATIVA', 'PESQUISA_UNIVERSIDADE')),
    CONSTRAINT CK_AMANAJE_CLI_ATIVO CHECK (ST_ATIVO IN ('S', 'N')),
    CONSTRAINT CK_AMANAJE_CLI_DEL CHECK (
        (ST_ATIVO = 'S' AND DT_DEL_EM IS NULL)
        OR
        (ST_ATIVO = 'N')
    )
);

COMMENT ON TABLE TB_AMANAJE_CLI IS 'Organizações que contratam, operam ou utilizam o serviço de monitoramento climático e ambiental.';
COMMENT ON COLUMN TB_AMANAJE_CLI.ID_CLIENTE IS 'Identificador único do cliente.';
COMMENT ON COLUMN TB_AMANAJE_CLI.NM_CLI IS 'Nome da instituição, organização, fazenda, cooperativa ou entidade de pesquisa.';
COMMENT ON COLUMN TB_AMANAJE_CLI.TP_CLI IS 'Tipo do cliente: GOVERNO_DEFESA_CIVIL, ONG, FAZENDA_PRIVADO, COOPERATIVA ou PESQUISA_UNIVERSIDADE.';
COMMENT ON COLUMN TB_AMANAJE_CLI.NR_DOCUMENTO IS 'Documento institucional do cliente, como CNPJ ou identificador equivalente.';
COMMENT ON COLUMN TB_AMANAJE_CLI.DS_EMAIL_CONTATO IS 'E-mail principal de contato do cliente.';
COMMENT ON COLUMN TB_AMANAJE_CLI.NR_TELEFONE IS 'Telefone principal de contato do cliente.';
COMMENT ON COLUMN TB_AMANAJE_CLI.ST_ATIVO IS 'Indica exclusão lógica do cliente: S = ativo, N = inativo.';
COMMENT ON COLUMN TB_AMANAJE_CLI.DT_CRIADO_EM IS 'Data e hora de criação do registro.';
COMMENT ON COLUMN TB_AMANAJE_CLI.DT_ATUALIZADO_EM IS 'Data e hora da última atualização do registro.';
COMMENT ON COLUMN TB_AMANAJE_CLI.DT_DEL_EM IS 'Data e hora da exclusão lógica.';
COMMENT ON COLUMN TB_AMANAJE_CLI.ID_DEL_POR IS 'Identificador do usuário que realizou a exclusão lógica, quando aplicável.';
COMMENT ON COLUMN TB_AMANAJE_CLI.DS_MOTIVO_EXCLUSAO IS 'Justificativa opcional para auditoria da exclusão lógica.';

CREATE TABLE TB_AMANAJE_USU (
