    CONSTRAINT CK_AMANAJE_USU_STATUS CHECK (ST_USU IN ('ATIVO', 'BLOQUEADO', 'PENDENTE', 'INATIVO')),
    CONSTRAINT CK_AMANAJE_USU_ATIVO CHECK (ST_ATIVO IN ('S', 'N')),
    CONSTRAINT CK_AMANAJE_USU_DEL CHECK (
        (ST_ATIVO = 'S' AND DT_DEL_EM IS NULL)
        OR
        (ST_ATIVO = 'N')
    ),
    CONSTRAINT FK_USU_CLI FOREIGN KEY (ID_CLIENTE)
        REFERENCES TB_AMANAJE_CLI (ID_CLIENTE),
    CONSTRAINT FK_USU_DEL_POR FOREIGN KEY (ID_DEL_POR)
        REFERENCES TB_AMANAJE_USU (ID_USUARIO)
);

