CREATE TABLE TB_AMANAJE_REGIAO_MONIT (
    ID_REGIAO NUMBER GENERATED BY DEFAULT AS IDENTITY,
    ID_CLIENTE NUMBER NOT NULL,
    NM_REGIAO VARCHAR2(150) NOT NULL,
    NM_CIDADE VARCHAR2(100) NOT NULL,
    SG_ESTADO CHAR(2) NOT NULL,
    NR_LATITUDE NUMBER(9,6) NOT NULL,
    NR_LONGITUDE NUMBER(9,6) NOT NULL,
    TP_AREA VARCHAR2(30) NOT NULL,
    NR_NIVEL_VULN NUMBER(3) NOT NULL,
    TP_VISIB VARCHAR2(20) DEFAULT 'PRIVADA' NOT NULL,
    ST_ATIVO CHAR(1) DEFAULT 'S' NOT NULL,
    DT_CRIADO_EM TIMESTAMP DEFAULT SYSTIMESTAMP NOT NULL,
    DT_ATUALIZADO_EM TIMESTAMP,
    DT_DEL_EM TIMESTAMP,
    ID_DEL_POR NUMBER,
    DS_MOTIVO_EXCLUSAO VARCHAR2(255),

    CONSTRAINT PK_AMANAJE_REGIAO PRIMARY KEY (ID_REGIAO),
    CONSTRAINT UQ_AMANAJE_REGIAO_CLI_NOME UNIQUE (ID_CLIENTE, NM_REGIAO),
    CONSTRAINT CK_AMANAJE_REGIAO_ESTADO CHECK (REGEXP_LIKE(SG_ESTADO, '^[A-Z]{2}$')),
    CONSTRAINT CK_AMANAJE_REGIAO_LAT CHECK (NR_LATITUDE BETWEEN -90 AND 90),
    CONSTRAINT CK_AMANAJE_REGIAO_LONG CHECK (NR_LONGITUDE BETWEEN -180 AND 180),
    CONSTRAINT CK_AMANAJE_REGIAO_AREA CHECK (TP_AREA IN ('PONTE', 'ENCOSTA', 'AREA_RURAL', 'COMUNIDADE', 'PROPRIEDADE_PRIVADA', 'REGIAO_RIBEIRINHA', 'AREA_URBANA', 'OUTRA')),
    CONSTRAINT CK_AMANAJE_REGIAO_VULN CHECK (NR_NIVEL_VULN BETWEEN 0 AND 100),
    CONSTRAINT CK_AMANAJE_REGIAO_VISIB CHECK (TP_VISIB IN ('PRIVADA', 'INSTITUCIONAL', 'AGREGADA_PUBLICA')),
    CONSTRAINT CK_AMANAJE_REGIAO_ATIVO CHECK (ST_ATIVO IN ('S', 'N')),
    CONSTRAINT CK_AMANAJE_REGIAO_DEL CHECK (
        (ST_ATIVO = 'S' AND DT_DEL_EM IS NULL)
        OR
        (ST_ATIVO = 'N')
    ),
    CONSTRAINT FK_REGIAO_CLI FOREIGN KEY (ID_CLIENTE)
        REFERENCES TB_AMANAJE_CLI (ID_CLIENTE),
    CONSTRAINT FK_REGIAO_DEL_POR FOREIGN KEY (ID_DEL_POR)
        REFERENCES TB_AMANAJE_USU (ID_USUARIO)
);

