CREATE TABLE TB_AMANAJE_EST_IOT (
    ID_ESTACAO NUMBER GENERATED BY DEFAULT AS IDENTITY,
    ID_REGIAO NUMBER NOT NULL,
    CD_EST VARCHAR2(40) NOT NULL,
    NM_EST VARCHAR2(120) NOT NULL,
    TP_EST VARCHAR2(20) NOT NULL,
    ST_EST VARCHAR2(20) DEFAULT 'ATIVA' NOT NULL,
    NR_LATITUDE NUMBER(9,6),
    NR_LONGITUDE NUMBER(9,6),
    DT_ULTIMA_COM TIMESTAMP,
    ST_ATIVO CHAR(1) DEFAULT 'S' NOT NULL,
    DT_CRIADO_EM TIMESTAMP DEFAULT SYSTIMESTAMP NOT NULL,
    DT_ATUALIZADO_EM TIMESTAMP,
    DT_DEL_EM TIMESTAMP,
    ID_DEL_POR NUMBER,
    DS_MOTIVO_EXCLUSAO VARCHAR2(255),

    CONSTRAINT PK_AMANAJE_EST PRIMARY KEY (ID_ESTACAO),
    CONSTRAINT UQ_AMANAJE_EST_CODIGO UNIQUE (CD_EST),
    CONSTRAINT UQ_AMANAJE_EST_ID_REGIAO UNIQUE (ID_ESTACAO, ID_REGIAO),
    CONSTRAINT CK_AMANAJE_EST_TIPO CHECK (TP_EST IN ('REAL', 'SIMULADA', 'REFERENCIA')),
    CONSTRAINT CK_AMANAJE_EST_STATUS CHECK (ST_EST IN ('ATIVA', 'INATIVA', 'MANUTENCAO', 'FALHA', 'SEM_COM')),
    CONSTRAINT CK_AMANAJE_EST_LAT CHECK (NR_LATITUDE IS NULL OR NR_LATITUDE BETWEEN -90 AND 90),
    CONSTRAINT CK_AMANAJE_EST_LONG CHECK (NR_LONGITUDE IS NULL OR NR_LONGITUDE BETWEEN -180 AND 180),
    CONSTRAINT CK_AMANAJE_EST_ATIVO CHECK (ST_ATIVO IN ('S', 'N')),
    CONSTRAINT CK_AMANAJE_EST_DEL CHECK (
        (ST_ATIVO = 'S' AND DT_DEL_EM IS NULL)
        OR
        (ST_ATIVO = 'N')
    ),
    CONSTRAINT FK_EST_REGIAO FOREIGN KEY (ID_REGIAO)
        REFERENCES TB_AMANAJE_REGIAO_MONIT (ID_REGIAO),
    CONSTRAINT FK_EST_DEL_POR FOREIGN KEY (ID_DEL_POR)
        REFERENCES TB_AMANAJE_USU (ID_USUARIO)
);

