COMMENT ON COLUMN TB_AMANAJE_OBS_CLIM.ID_OBSERVACAO IS 'Identificador único da observação climática externa.';
COMMENT ON COLUMN TB_AMANAJE_OBS_CLIM.ID_REGIAO IS 'Região monitorada relacionada à observação climática.';
COMMENT ON COLUMN TB_AMANAJE_OBS_CLIM.NM_FONTE IS 'Fonte pública ou serviço usado para obter os dados climáticos.';
COMMENT ON COLUMN TB_AMANAJE_OBS_CLIM.NR_TEMPERATURA_C IS 'Temperatura em graus Celsius.';
COMMENT ON COLUMN TB_AMANAJE_OBS_CLIM.NR_UMIDADE_PCT IS 'Umidade relativa do ar em percentual.';
COMMENT ON COLUMN TB_AMANAJE_OBS_CLIM.NR_PRECIP_MM IS 'Precipitação em milímetros.';
COMMENT ON COLUMN TB_AMANAJE_OBS_CLIM.NR_VENTO_KMH IS 'Velocidade do vento em km/h.';
COMMENT ON COLUMN TB_AMANAJE_OBS_CLIM.NR_PRESSAO_HPA IS 'Pressão atmosférica externa em hPa.';
COMMENT ON COLUMN TB_AMANAJE_OBS_CLIM.NR_RADIACAO_SOLAR IS 'Radiação solar informada pela fonte externa.';
COMMENT ON COLUMN TB_AMANAJE_OBS_CLIM.NR_INDICE_UV IS 'Índice ultravioleta informado pela fonte externa.';
COMMENT ON COLUMN TB_AMANAJE_OBS_CLIM.DT_OBS IS 'Data e hora da observação climática externa.';
COMMENT ON COLUMN TB_AMANAJE_OBS_CLIM.DT_CRIADO_EM IS 'Data e hora de criação do registro no banco.';

CREATE TABLE TB_AMANAJE_AVAL_RISCO (
    ID_AVALIACAO NUMBER GENERATED BY DEFAULT AS IDENTITY,
    ID_REGIAO NUMBER NOT NULL,
    ID_LEITURA NUMBER,
    ID_OBSERVACAO NUMBER,
    TP_RISCO VARCHAR2(30) NOT NULL,
    NR_SCORE_RISCO NUMBER(5,2) NOT NULL,
    TP_NIVEL_RISCO VARCHAR2(20) NOT NULL,
    DS_MOTIVO VARCHAR2(500) NOT NULL,
    DT_AVAL TIMESTAMP DEFAULT SYSTIMESTAMP NOT NULL,

    CONSTRAINT PK_AMANAJE_AVAL PRIMARY KEY (ID_AVALIACAO),
    CONSTRAINT UQ_AMANAJE_AVAL_ID_REGIAO UNIQUE (ID_AVALIACAO, ID_REGIAO),
    CONSTRAINT CK_AMANAJE_AVAL_TIPO CHECK (TP_RISCO IN ('ENCHENTE', 'DESLIZAMENTO', 'TEMPESTADE', 'QUALIDADE_AR')),
    CONSTRAINT CK_AMANAJE_AVAL_SCORE CHECK (NR_SCORE_RISCO BETWEEN 0 AND 100),
    CONSTRAINT CK_AMANAJE_AVAL_NIVEL CHECK (TP_NIVEL_RISCO IN ('BAIXO', 'MODERADO', 'ALTO', 'CRITICO')),
    CONSTRAINT CK_AMANAJE_AVAL_ORIGEM CHECK (ID_LEITURA IS NOT NULL OR ID_OBSERVACAO IS NOT NULL),
    CONSTRAINT CK_AMANAJE_AVAL_SCORE_NIV CHECK (
        (TP_NIVEL_RISCO = 'BAIXO' AND NR_SCORE_RISCO >= 0 AND NR_SCORE_RISCO < 25)
        OR
        (TP_NIVEL_RISCO = 'MODERADO' AND NR_SCORE_RISCO >= 25 AND NR_SCORE_RISCO < 50)
        OR
        (TP_NIVEL_RISCO = 'ALTO' AND NR_SCORE_RISCO >= 50 AND NR_SCORE_RISCO < 75)
        OR
        (TP_NIVEL_RISCO = 'CRITICO' AND NR_SCORE_RISCO >= 75 AND NR_SCORE_RISCO <= 100)
    ),
    CONSTRAINT FK_AVAL_REGIAO FOREIGN KEY (ID_REGIAO)
        REFERENCES TB_AMANAJE_REGIAO_MONIT (ID_REGIAO),
    CONSTRAINT FK_AVAL_LEIT_REGIAO FOREIGN KEY (ID_LEITURA, ID_REGIAO)
        REFERENCES TB_AMANAJE_LEIT_IOT (ID_LEITURA, ID_REGIAO),
    CONSTRAINT FK_AVAL_OBS_REGIAO FOREIGN KEY (ID_OBSERVACAO, ID_REGIAO)
        REFERENCES TB_AMANAJE_OBS_CLIM (ID_OBSERVACAO, ID_REGIAO)
);

COMMENT ON TABLE TB_AMANAJE_AVAL_RISCO IS 'Resultados calculados pela API para risco ambiental por região e categoria.';
COMMENT ON COLUMN TB_AMANAJE_AVAL_RISCO.ID_AVALIACAO IS 'Identificador único da avaliação de risco.';
COMMENT ON COLUMN TB_AMANAJE_AVAL_RISCO.ID_REGIAO IS 'Região monitorada avaliada.';
COMMENT ON COLUMN TB_AMANAJE_AVAL_RISCO.ID_LEITURA IS 'Leitura IoT usada na avaliação, quando aplicável.';
COMMENT ON COLUMN TB_AMANAJE_AVAL_RISCO.ID_OBSERVACAO IS 'Observação climática externa usada na avaliação, quando aplicável.';
COMMENT ON COLUMN TB_AMANAJE_AVAL_RISCO.TP_RISCO IS 'Categoria do risco ambiental avaliado.';
COMMENT ON COLUMN TB_AMANAJE_AVAL_RISCO.NR_SCORE_RISCO IS 'Score de risco calculado entre 0 e 100.';
COMMENT ON COLUMN TB_AMANAJE_AVAL_RISCO.TP_NIVEL_RISCO IS 'Nível do risco: BAIXO, MODERADO, ALTO ou CRITICO.';
COMMENT ON COLUMN TB_AMANAJE_AVAL_RISCO.DS_MOTIVO IS 'Justificativa resumida para o score e nível de risco.';
COMMENT ON COLUMN TB_AMANAJE_AVAL_RISCO.DT_AVAL IS 'Data e hora da avaliação de risco.';

CREATE TABLE TB_AMANAJE_ALERTA (
    ID_ALERTA NUMBER GENERATED BY DEFAULT AS IDENTITY,
    ID_REGIAO NUMBER NOT NULL,
    ID_AVALIACAO NUMBER NOT NULL,
    TP_ALERTA VARCHAR2(30) NOT NULL,
    TP_NIVEL VARCHAR2(20) NOT NULL,
    DS_TITULO VARCHAR2(150) NOT NULL,
    DS_ALERTA VARCHAR2(1000) NOT NULL,
    DS_RECOM VARCHAR2(1000) NOT NULL,
    ST_ALERTA VARCHAR2(20) DEFAULT 'ABERTO' NOT NULL,
    DT_ALERTA TIMESTAMP DEFAULT SYSTIMESTAMP NOT NULL,
    DT_RESOLVIDO_EM TIMESTAMP,
    ST_ATIVO CHAR(1) DEFAULT 'S' NOT NULL,
    DT_CRIADO_EM TIMESTAMP DEFAULT SYSTIMESTAMP NOT NULL,
    DT_ATUALIZADO_EM TIMESTAMP,
    DT_DEL_EM TIMESTAMP,
    ID_DEL_POR NUMBER,
    DS_MOTIVO_EXCLUSAO VARCHAR2(255),

    CONSTRAINT PK_AMANAJE_ALERTA PRIMARY KEY (ID_ALERTA),
    CONSTRAINT CK_AMANAJE_ALERTA_TIPO CHECK (TP_ALERTA IN ('ENCHENTE', 'DESLIZAMENTO', 'TEMPESTADE', 'QUALIDADE_AR', 'OPERACIONAL')),
    CONSTRAINT CK_AMANAJE_ALERTA_NIVEL CHECK (TP_NIVEL IN ('BAIXO', 'MODERADO', 'ALTO', 'CRITICO')),
    CONSTRAINT CK_AMANAJE_ALERTA_STATUS CHECK (ST_ALERTA IN ('ABERTO', 'EM_ANALISE', 'RESOLVIDO', 'CANCELADO')),
    CONSTRAINT CK_AMANAJE_ALERTA_ATIVO CHECK (ST_ATIVO IN ('S', 'N')),
    CONSTRAINT CK_AMANAJE_ALERTA_RES CHECK (
        (ST_ALERTA = 'RESOLVIDO' AND DT_RESOLVIDO_EM IS NOT NULL)
        OR
        (ST_ALERTA <> 'RESOLVIDO')
    ),
    CONSTRAINT CK_AMANAJE_ALERTA_DEL CHECK (
        (ST_ATIVO = 'S' AND DT_DEL_EM IS NULL)
        OR
        (ST_ATIVO = 'N')
    ),
    CONSTRAINT FK_ALERTA_REGIAO FOREIGN KEY (ID_REGIAO)
        REFERENCES TB_AMANAJE_REGIAO_MONIT (ID_REGIAO),
    CONSTRAINT FK_ALERTA_AVAL_REGIAO FOREIGN KEY (ID_AVALIACAO, ID_REGIAO)
        REFERENCES TB_AMANAJE_AVAL_RISCO (ID_AVALIACAO, ID_REGIAO),
    CONSTRAINT FK_ALERTA_DEL_POR FOREIGN KEY (ID_DEL_POR)
        REFERENCES TB_AMANAJE_USU (ID_USUARIO)
);

COMMENT ON TABLE TB_AMANAJE_ALERTA IS 'Alertas gerados a partir de avaliações de risco para apoio à decisão institucional.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.ID_ALERTA IS 'Identificador único do alerta.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.ID_REGIAO IS 'Região monitorada relacionada ao alerta.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.ID_AVALIACAO IS 'Avaliação de risco que originou o alerta.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.TP_ALERTA IS 'Tipo do alerta ambiental ou operacional.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.TP_NIVEL IS 'Nível do alerta.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.DS_TITULO IS 'Título curto exibido em dashboard.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.DS_ALERTA IS 'Descrição detalhada do alerta.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.DS_RECOM IS 'Recomendação operacional associada ao alerta.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.ST_ALERTA IS 'Status do ciclo de vida do alerta.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.DT_ALERTA IS 'Data e hora de criação do alerta.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.DT_RESOLVIDO_EM IS 'Data e hora de resolução do alerta.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.ST_ATIVO IS 'Indica exclusão lógica do alerta: S = ativo, N = inativo.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.DT_CRIADO_EM IS 'Data e hora de criação do registro.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.DT_ATUALIZADO_EM IS 'Data e hora da última atualização do registro.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.DT_DEL_EM IS 'Data e hora da exclusão lógica.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.ID_DEL_POR IS 'Identificador do usuário que realizou a exclusão lógica, quando aplicável.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.DS_MOTIVO_EXCLUSAO IS 'Justificativa opcional para auditoria da exclusão lógica.';

CREATE TABLE TB_AMANAJE_IND_REG (
    ID_INDICADOR NUMBER GENERATED BY DEFAULT AS IDENTITY,
    ID_REGIAO NUMBER,
    SG_ESTADO CHAR(2) NOT NULL,
    NM_CIDADE VARCHAR2(100) NOT NULL,
    NM_REGIAO VARCHAR2(150),
    TP_RISCO VARCHAR2(30) NOT NULL,
    NR_SCORE_MEDIO NUMBER(5,2) NOT NULL,
    TP_NIVEL_RISCO_MEDIO VARCHAR2(20) NOT NULL,
    QT_ESTACOES NUMBER(6) DEFAULT 0 NOT NULL,
    QT_ALERTAS_ATIVOS NUMBER(6) DEFAULT 0 NOT NULL,
    NM_FONTE_CALCULO VARCHAR2(100) NOT NULL,
    DT_CALCULO TIMESTAMP DEFAULT SYSTIMESTAMP NOT NULL,

    CONSTRAINT PK_AMANAJE_IND PRIMARY KEY (ID_INDICADOR),
    CONSTRAINT CK_AMANAJE_IND_ESTADO CHECK (REGEXP_LIKE(SG_ESTADO, '^[A-Z]{2}$')),
    CONSTRAINT CK_AMANAJE_IND_TIPO CHECK (TP_RISCO IN ('ENCHENTE', 'DESLIZAMENTO', 'TEMPESTADE', 'QUALIDADE_AR')),
    CONSTRAINT CK_AMANAJE_IND_SCORE CHECK (NR_SCORE_MEDIO BETWEEN 0 AND 100),
    CONSTRAINT CK_AMANAJE_IND_NIVEL CHECK (TP_NIVEL_RISCO_MEDIO IN ('BAIXO', 'MODERADO', 'ALTO', 'CRITICO')),
    CONSTRAINT CK_AMANAJE_IND_EST CHECK (QT_ESTACOES >= 0),
    CONSTRAINT CK_AMANAJE_IND_ALT CHECK (QT_ALERTAS_ATIVOS >= 0),
    CONSTRAINT CK_AMANAJE_IND_SCORE_NIV CHECK (
        (TP_NIVEL_RISCO_MEDIO = 'BAIXO' AND NR_SCORE_MEDIO >= 0 AND NR_SCORE_MEDIO < 25)
        OR
        (TP_NIVEL_RISCO_MEDIO = 'MODERADO' AND NR_SCORE_MEDIO >= 25 AND NR_SCORE_MEDIO < 50)
        OR
        (TP_NIVEL_RISCO_MEDIO = 'ALTO' AND NR_SCORE_MEDIO >= 50 AND NR_SCORE_MEDIO < 75)
        OR
        (TP_NIVEL_RISCO_MEDIO = 'CRITICO' AND NR_SCORE_MEDIO >= 75 AND NR_SCORE_MEDIO <= 100)
    ),
    CONSTRAINT FK_IND_REGIAO FOREIGN KEY (ID_REGIAO)
        REFERENCES TB_AMANAJE_REGIAO_MONIT (ID_REGIAO)
);

COMMENT ON TABLE TB_AMANAJE_IND_REG IS 'Indicadores agregados por cidade, estado ou zona de risco, sem exposição de dados privados identificáveis.';
COMMENT ON COLUMN TB_AMANAJE_IND_REG.ID_INDICADOR IS 'Identificador único do indicador regional.';
COMMENT ON COLUMN TB_AMANAJE_IND_REG.ID_REGIAO IS 'Região monitorada relacionada ao indicador, quando houver vínculo direto.';
COMMENT ON COLUMN TB_AMANAJE_IND_REG.SG_ESTADO IS 'Sigla da unidade federativa do indicador.';
COMMENT ON COLUMN TB_AMANAJE_IND_REG.NM_CIDADE IS 'Cidade agregada no indicador.';
COMMENT ON COLUMN TB_AMANAJE_IND_REG.NM_REGIAO IS 'Nome agregado da região, quando aplicável.';
COMMENT ON COLUMN TB_AMANAJE_IND_REG.TP_RISCO IS 'Tipo de risco consolidado no indicador.';
COMMENT ON COLUMN TB_AMANAJE_IND_REG.NR_SCORE_MEDIO IS 'Score médio calculado para o indicador.';
COMMENT ON COLUMN TB_AMANAJE_IND_REG.TP_NIVEL_RISCO_MEDIO IS 'Nível médio de risco associado ao score médio.';
COMMENT ON COLUMN TB_AMANAJE_IND_REG.QT_ESTACOES IS 'Quantidade de estações consideradas no cálculo.';
COMMENT ON COLUMN TB_AMANAJE_IND_REG.QT_ALERTAS_ATIVOS IS 'Quantidade de alertas ativos considerados no cálculo.';
COMMENT ON COLUMN TB_AMANAJE_IND_REG.NM_FONTE_CALCULO IS 'Origem ou rotina responsável pelo cálculo do indicador.';
COMMENT ON COLUMN TB_AMANAJE_IND_REG.DT_CALCULO IS 'Data e hora do cálculo do indicador.';

CREATE TABLE TB_AMANAJE_HIST_EVENTO (
    ID_EVENTO NUMBER GENERATED BY DEFAULT AS IDENTITY,
    ID_USUARIO NUMBER,
    NM_ENTIDADE VARCHAR2(80) NOT NULL,
    ID_ENTIDADE NUMBER NOT NULL,
    TP_ACAO VARCHAR2(30) NOT NULL,
    DS_EVENTO VARCHAR2(1000) NOT NULL,
    DT_EVENTO TIMESTAMP DEFAULT SYSTIMESTAMP NOT NULL,

    CONSTRAINT PK_AMANAJE_HIST_EVENTO PRIMARY KEY (ID_EVENTO),
    CONSTRAINT CK_AMANAJE_HIST_ACAO CHECK (TP_ACAO IN ('CRIACAO', 'ATUALIZACAO', 'EXCLUSAO_LOGICA', 'INVAL', 'AVAL_RISCO', 'GERACAO_ALERTA', 'RESOLUCAO_ALERTA', 'LOGIN', 'INTEGRACAO_EXTERNA', 'OUTRA')),
    CONSTRAINT FK_HIST_USU FOREIGN KEY (ID_USUARIO)
        REFERENCES TB_AMANAJE_USU (ID_USUARIO)
);

COMMENT ON TABLE TB_AMANAJE_HIST_EVENTO IS 'Registro genérico de ações relevantes para rastreabilidade e auditoria.';
COMMENT ON COLUMN TB_AMANAJE_HIST_EVENTO.ID_EVENTO IS 'Identificador único do evento histórico.';
COMMENT ON COLUMN TB_AMANAJE_HIST_EVENTO.ID_USUARIO IS 'Usuário associado ao evento, quando aplicável.';
COMMENT ON COLUMN TB_AMANAJE_HIST_EVENTO.NM_ENTIDADE IS 'Nome lógico da entidade afetada pelo evento.';
COMMENT ON COLUMN TB_AMANAJE_HIST_EVENTO.ID_ENTIDADE IS 'Identificador do registro afetado na entidade de origem.';
COMMENT ON COLUMN TB_AMANAJE_HIST_EVENTO.TP_ACAO IS 'Tipo de ação registrada.';
COMMENT ON COLUMN TB_AMANAJE_HIST_EVENTO.DS_EVENTO IS 'Descrição do evento para auditoria.';
COMMENT ON COLUMN TB_AMANAJE_HIST_EVENTO.DT_EVENTO IS 'Data e hora de ocorrência do evento.';

CREATE TABLE TB_AMANAJE_LOG_STATUS_EST (
    ID_LOG NUMBER GENERATED BY DEFAULT AS IDENTITY,
    ID_ESTACAO NUMBER NOT NULL,
    NR_UPTIME_SEG NUMBER(12),
    NR_RSSI NUMBER(6,2),
    DS_IP_ADDRESS VARCHAR2(45),
    DS_VERSAO_FIRMWARE VARCHAR2(40),
    DT_REGISTRO TIMESTAMP DEFAULT SYSTIMESTAMP NOT NULL,

    CONSTRAINT PK_AMANAJE_LOG_EST PRIMARY KEY (ID_LOG),
    CONSTRAINT CK_AMANAJE_LOG_UPTIME CHECK (NR_UPTIME_SEG IS NULL OR NR_UPTIME_SEG >= 0),
    CONSTRAINT FK_LOG_EST FOREIGN KEY (ID_ESTACAO)
        REFERENCES TB_AMANAJE_EST_IOT (ID_ESTACAO)
);

COMMENT ON TABLE TB_AMANAJE_LOG_STATUS_EST IS 'Histórico de mensagens de diagnóstico técnico e integridade das estações IoT.';
COMMENT ON COLUMN TB_AMANAJE_LOG_STATUS_EST.ID_LOG IS 'Identificador único do log de status.';
COMMENT ON COLUMN TB_AMANAJE_LOG_STATUS_EST.ID_ESTACAO IS 'Estação IoT relacionada ao log.';
COMMENT ON COLUMN TB_AMANAJE_LOG_STATUS_EST.NR_UPTIME_SEG IS 'Tempo de atividade da estação em segundos.';
COMMENT ON COLUMN TB_AMANAJE_LOG_STATUS_EST.NR_RSSI IS 'Intensidade do sinal Wi-Fi ou rádio informada pela estação.';
COMMENT ON COLUMN TB_AMANAJE_LOG_STATUS_EST.DS_IP_ADDRESS IS 'Endereço IP informado pela estação.';
COMMENT ON COLUMN TB_AMANAJE_LOG_STATUS_EST.DS_VERSAO_FIRMWARE IS 'Versão de firmware da estação.';
COMMENT ON COLUMN TB_AMANAJE_LOG_STATUS_EST.DT_REGISTRO IS 'Data e hora de registro do status.';

CREATE TABLE TB_AMANAJE_PROCESS (
    ID_PROCESSAMENTO NUMBER GENERATED BY DEFAULT AS IDENTITY,
    ID_REGIAO NUMBER,
    ID_USUARIO NUMBER,
    TP_PROCESS VARCHAR2(40) NOT NULL,
    ST_PROCESS VARCHAR2(20) DEFAULT 'INICIADO' NOT NULL,
    DS_ORIGEM VARCHAR2(120) NOT NULL,
    DS_PARAM VARCHAR2(1000),
    DS_RESULT VARCHAR2(1000),
    DT_INICIO TIMESTAMP DEFAULT SYSTIMESTAMP NOT NULL,
    DT_FIM TIMESTAMP,

    CONSTRAINT PK_AMANAJE_PROCESS PRIMARY KEY (ID_PROCESSAMENTO),
    CONSTRAINT CK_AMANAJE_PROCESS_TIPO CHECK (TP_PROCESS IN ('SINCRONIZACAO_CLIM', 'CALCULO_RISCO', 'GERACAO_IND', 'GERACAO_ALERTA', 'CARGA_DADOS', 'ROTINA_PL_SQL', 'OUTRO')),
    CONSTRAINT CK_AMANAJE_PROCESS_STATUS CHECK (ST_PROCESS IN ('INICIADO', 'EM_EXECUCAO', 'CONCLUIDO', 'FALHOU', 'CANCELADO')),
    CONSTRAINT CK_AMANAJE_PROCESS_FIM CHECK (DT_FIM IS NULL OR DT_FIM >= DT_INICIO),
    CONSTRAINT FK_PROCESS_REGIAO FOREIGN KEY (ID_REGIAO)
        REFERENCES TB_AMANAJE_REGIAO_MONIT (ID_REGIAO),
    CONSTRAINT FK_PROCESS_USU FOREIGN KEY (ID_USUARIO)
        REFERENCES TB_AMANAJE_USU (ID_USUARIO)
);

COMMENT ON TABLE TB_AMANAJE_PROCESS IS 'Registro de execuções e processamentos, como sincronização climática, cálculo de risco, geração de indicadores e rotinas PL/SQL.';
COMMENT ON COLUMN TB_AMANAJE_PROCESS.ID_PROCESSAMENTO IS 'Identificador único do processamento.';
COMMENT ON COLUMN TB_AMANAJE_PROCESS.ID_REGIAO IS 'Região monitorada relacionada ao processamento, quando aplicável.';
COMMENT ON COLUMN TB_AMANAJE_PROCESS.ID_USUARIO IS 'Usuário responsável ou associado ao processamento, quando aplicável.';
COMMENT ON COLUMN TB_AMANAJE_PROCESS.TP_PROCESS IS 'Tipo de processamento executado pelo sistema.';
COMMENT ON COLUMN TB_AMANAJE_PROCESS.ST_PROCESS IS 'Status atual da execução do processamento.';
COMMENT ON COLUMN TB_AMANAJE_PROCESS.DS_ORIGEM IS 'Origem do processamento, como API Java, serviço C#, carga DML ou bloco PL/SQL.';
COMMENT ON COLUMN TB_AMANAJE_PROCESS.DS_PARAM IS 'Parâmetros de entrada usados na execução.';
COMMENT ON COLUMN TB_AMANAJE_PROCESS.DS_RESULT IS 'Resultado resumido da execução.';
COMMENT ON COLUMN TB_AMANAJE_PROCESS.DT_INICIO IS 'Data e hora de início do processamento.';
COMMENT ON COLUMN TB_AMANAJE_PROCESS.DT_FIM IS 'Data e hora de término do processamento.';

CREATE TABLE TB_AMANAJE_LOG_ERRO (
    ID_LOG_ERRO NUMBER GENERATED BY DEFAULT AS IDENTITY,
    ID_PROCESSAMENTO NUMBER,
    ID_USUARIO NUMBER,
    NM_ORIGEM VARCHAR2(120) NOT NULL,
    NM_OBJETO VARCHAR2(120),
    CD_ERRO NUMBER,
    DS_ERRO VARCHAR2(1000) NOT NULL,
    DS_COMANDO VARCHAR2(4000),
    DT_ERRO TIMESTAMP DEFAULT SYSTIMESTAMP NOT NULL,

    CONSTRAINT PK_AMANAJE_LOG_ERRO PRIMARY KEY (ID_LOG_ERRO),
    CONSTRAINT FK_LOG_ERRO_PROCESS FOREIGN KEY (ID_PROCESSAMENTO)
        REFERENCES TB_AMANAJE_PROCESS (ID_PROCESSAMENTO),
    CONSTRAINT FK_LOG_ERRO_USU FOREIGN KEY (ID_USUARIO)
        REFERENCES TB_AMANAJE_USU (ID_USUARIO)
);

COMMENT ON TABLE TB_AMANAJE_LOG_ERRO IS 'Registro técnico de erros ocorridos em cargas, blocos PL/SQL, integrações e processamentos do banco.';
COMMENT ON COLUMN TB_AMANAJE_LOG_ERRO.ID_LOG_ERRO IS 'Identificador único do log de erro.';
COMMENT ON COLUMN TB_AMANAJE_LOG_ERRO.ID_PROCESSAMENTO IS 'Processamento relacionado ao erro, quando aplicável.';
COMMENT ON COLUMN TB_AMANAJE_LOG_ERRO.ID_USUARIO IS 'Usuário associado ao erro, quando aplicável.';
COMMENT ON COLUMN TB_AMANAJE_LOG_ERRO.NM_ORIGEM IS 'Origem do erro, como DML, PL/SQL, API, integração externa ou rotina de carga.';
COMMENT ON COLUMN TB_AMANAJE_LOG_ERRO.NM_OBJETO IS 'Nome do objeto ou bloco relacionado ao erro.';
COMMENT ON COLUMN TB_AMANAJE_LOG_ERRO.CD_ERRO IS 'Código técnico do erro, quando disponível.';
COMMENT ON COLUMN TB_AMANAJE_LOG_ERRO.DS_ERRO IS 'Descrição técnica do erro ocorrido.';
COMMENT ON COLUMN TB_AMANAJE_LOG_ERRO.DS_COMANDO IS 'Comando, etapa ou instrução relacionada ao erro, quando aplicável.';
COMMENT ON COLUMN TB_AMANAJE_LOG_ERRO.DT_ERRO IS 'Data e hora de registro do erro.';

