CREATE INDEX IX_AMANAJE_EST_REGIAO ON TB_AMANAJE_EST_IOT (ID_REGIAO);
CREATE INDEX IX_AMANAJE_EST_DEL_POR ON TB_AMANAJE_EST_IOT (ID_DEL_POR);
CREATE INDEX IX_AMANAJE_EST_STATUS ON TB_AMANAJE_EST_IOT (ST_EST);
