CREATE INDEX IX_AMANAJE_LEIT_REGIAO ON TB_AMANAJE_LEIT_IOT (ID_REGIAO);
CREATE INDEX IX_AMANAJE_LEIT_DATA ON TB_AMANAJE_LEIT_IOT (DT_LEIT);
CREATE INDEX IX_AMANAJE_LEIT_VALIDA ON TB_AMANAJE_LEIT_IOT (ST_VALIDA);
CREATE INDEX IX_AMANAJE_OBS_REGIAO ON TB_AMANAJE_OBS_CLIM (ID_REGIAO);
CREATE INDEX IX_AMANAJE_OBS_DATA ON TB_AMANAJE_OBS_CLIM (DT_OBS);
CREATE INDEX IX_AMANAJE_AVAL_REGIAO ON TB_AMANAJE_AVAL_RISCO (ID_REGIAO);
CREATE INDEX IX_AMANAJE_AVAL_LEIT ON TB_AMANAJE_AVAL_RISCO (ID_LEITURA);
